// ----- Computed field shapes ------------------------------------------------

/** Derived fields for shifts */
export interface ShiftsComputed {
  /** COUNT(assignments WHERE shift_id = this.id) */
  assigned_count: number;
  /** (ends_at − starts_at) / 1 hour */
  duration_hours: number;
  /** assigned_count − required_count */
  coverage_delta: number;
  /** IF(assigned < required, 'under', IF(assigned > required, 'over', 'full')) */
  coverage_status: string;
  /** AVG(assigned_volunteers.reliability_score) */
  weighted_reliability: number;
  /** IF(required_skill IS NULL, NULL, COUNT(assigned WHERE has(required_skill)) / COUNT(assigned)) */
  skill_match_pct: number | null;
}

/** Derived fields for events */
export interface EventsComputed {
  /** COUNT(shifts WHERE event_id = this.id) */
  shift_count: number;
  /** SUM(shifts.required_count WHERE event_id = this.id) */
  total_required: number;
  /** SUM(shifts.assigned_count WHERE event_id = this.id) */
  total_assigned: number;
  /** IF(total_required = 0, 1, total_assigned / total_required) */
  coverage_pct: number;
  /** COUNT(shifts WHERE event_id = this.id AND coverage_status = 'under') */
  understaffed_shift_count: number;
  /** COUNT(shifts WHERE event_id = this.id AND coverage_status = 'over') */
  overstaffed_shift_count: number;
  /** COUNT(shifts WHERE event_id = this.id AND coverage_status = 'full') */
  fully_staffed_shift_count: number;
  /** COUNT(DISTINCT assignments.volunteer_id WHERE shift.event_id = this.id) */
  volunteer_count: number;
  /** AVG(reliability_score) over distinct assigned volunteers */
  avg_reliability: number;
  /** AVG(shifts.skill_match_pct WHERE skill_match_pct IS NOT NULL) */
  skill_match_avg: number;
  /** GRADE_WEIGHTS.coverage_pct · min(1, coverage_pct) + GRADE_WEIGHTS.avg_reliability · avg_reliability + GRADE_WEIGHTS.skill_match_avg · skill_match_avg */
  score: number;
  /** first(band ∈ GRADE_BANDS WHERE score ≥ band.min).grade */
  grade: string;
}

/** Derived fields for volunteer_event */
export interface VolunteerEventComputed {
  /** SUM(shift.duration_hours WHERE shift.event_id = event.id AND assigned(volunteer, shift)) */
  assigned_hours: number;
  /** COUNT(shifts WHERE event_id = event.id AND assigned(volunteer, shift)) */
  shift_count: number;
  /** IF(assigned_hours = 0, 'unassigned', IF(assigned_hours > volunteer.max_hours OR assigned_hours > LOAD_BANDS.over_factor × event.target_hours_per_volunteer, 'over', IF(assigned_hours < LOAD_BANDS.under_factor × event.target_hours_per_volunteer, 'under', 'ok'))) */
  load_status: string;
}

